import { css } from '@emotion/css'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import shallow from 'zustand/shallow'
import { GameSettingsGomokuSize } from '../component/GomokuSizeSetting'
import { GomokuContextType } from '../context/Provider'

export const GameSettings: React.FC = () => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [MAX_ROW, gameStatus, action] = useGomokuStore(
    ({ state, action }) => [state.MAX_ROW, state.gameStatus, action],
    shallow,
  )
  const events = {
    onSizeChange: useEvent((size: number): void => action.reset({ MAX_ROW: size, MAX_COL: size })),
  }

  const isPending: boolean = gameStatus === GameRunningStatus.PENDING
  const classes = useStyles()

  return (
    <div className={classes.container}>
      <GameSettingsGomokuSize
        className={classes.item}
        size={MAX_ROW}
        disabled={!isPending}
        onSizeChange={events.onSizeChange}
      />
    </div>
  )
}

const useStyles = () => {
  return {
    container: css({
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between',
      margin: 'auto',
    }),
    item: css({
      lineHeight: '3rem',
    }),
  }
}
