import { sleep } from '@kyokuya/core-util'
import type { GomokuPlayerType } from '../../core/constant'
import type { IMoveContext, IPlayer } from '../../types'

export interface IBasePlayerProps {
  MINIMAL_THINKING_TIME?: number
}

export abstract class BasePlayer implements IPlayer {
  public abstract readonly type: GomokuPlayerType
  public abstract readonly automatic: boolean
  public readonly MINIMAL_THINKING_TIME: number

  constructor(props: IBasePlayerProps) {
    const MINIMAL_THINKING_TIME = Math.min(300000, props.MINIMAL_THINKING_TIME ?? 0)
    this.MINIMAL_THINKING_TIME = MINIMAL_THINKING_TIME
  }

  public async move(ctx: IMoveContext): Promise<[r: number, c: number]> {
    const startTime: number = Date.now()
    const result = this._move(ctx)
    const duration: number = startTime + this.MINIMAL_THINKING_TIME - Date.now()
    if (duration > 0) await sleep(duration)
    return result
  }

  protected abstract _move(
    ctx: IMoveContext,
  ): [r: number, c: number] | Promise<[r: number, c: number]>
}
