import { css } from '@emotion/css'
import React from 'react'
import { DuelPlayerContainer } from './container/DuelPlayerContainer'
import { GameBoard } from './container/GameBoard'
import { GameOverlay } from './container/GameOverlay'
import { GameSettings } from './container/GameSettings'
import { GameToolbar } from './container/GameToolbar'
import { GomokuContextType } from './context/Provider'

export const GomokuGameMain: React.FC = () => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [action] = useGomokuStore(store => [store.action])
  const containerRef = React.useRef<HTMLDivElement>(null)
  const classes = useStyles()

  React.useEffect(() => {
    const beforeunload = (): void => action.pause()
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [action])

  return (
    <div ref={containerRef} className={classes.container}>
      <div className={classes.header}>
        <GameSettings />
        <DuelPlayerContainer containerRef={containerRef} />
        <GameToolbar containerRef={containerRef} />
      </div>
      <div className={classes.main}>
        <GameBoard overlay={<GameOverlay />} />
      </div>
    </div>
  )
}

const useStyles = () => ({
  container: css`
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    width: 100%;
  `,
  header: css`
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    justify-content: center;
    width: 100%;
    padding: 2vmin;
  `,
  main: css`
    box-sizing: border-box;
    height: 96vmin;
    width: 96vmin;
    background-color: #c6a27e;
    background-size: cover;

    @media (min-width: 1367px) {
      width: 60vmin;
      height: 60vmin;
    }
  `,
})
