import type { IStatePatcher, ISyncStatePatcher, ISyncStateReplacer } from '@kyokuya/core-util'
import { createStatePatcher, isPromise } from '@kyokuya/core-util'
import create from 'zustand'
import type { IGomokuAction } from './action'
import { createGomokuAction } from './action'
import type { IGomokuState } from './state'
import { initGomokuState } from './state'

export interface IGomokuStore {
  state: IGomokuState
  action: IGomokuAction
  patch: IStatePatcher<IGomokuState>
  syncPatch: ISyncStatePatcher<IGomokuState>
  syncReplace: ISyncStateReplacer<IGomokuState>
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
export const createGomokuStore = (
  initialState: Partial<IGomokuState> | Promise<Partial<IGomokuState>> | null,
) => {
  return create<IGomokuStore>((set, get) => {
    const state0: IGomokuState = initGomokuState(isPromise(initialState) ? {} : initialState ?? {})
    if (isPromise(initialState)) {
      void initialState.then(state => {
        if (get().state === state0) set({ state: initGomokuState(state) })
      })
    }

    const [patch, syncPatch, syncReplace] = createStatePatcher<IGomokuState, IGomokuStore>(get, set)
    const action: IGomokuAction = createGomokuAction({ get, set, patch, syncPatch })
    return { state: state0, action, patch, syncPatch, syncReplace }
  })
}
