import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import type { StateListener } from 'zustand'
import shallow from 'zustand/shallow'
import type { IGomokuState as IState } from './state'
import type { IGomokuStore } from './store'
import { createGomokuStore } from './store'

type IUseGomokuStore = ReturnType<typeof createGomokuStore>

export interface IGomokuContext {
  useGomokuStore: IUseGomokuStore
}

export const GomokuContextType: React.Context<IGomokuContext> = React.createContext<IGomokuContext>(
  {
    useGomokuStore: ((): void => {
      throw new Error('[GomokuContext] `useGomokuStore` not available yet.')
    }) as IUseGomokuStore,
  },
)

export interface IGomokuContextProviderProps {
  initialState: IState | null
  children: React.ReactNode
  onStateChange?(state: IState): Promise<void> | void
}

export const GomokuContextProvider: React.FC<IGomokuContextProviderProps> = props => {
  const { initialState } = props
  const [useGomokuStore] = React.useState<IUseGomokuStore>(() => createGomokuStore(initialState))
  const context = React.useMemo<IGomokuContext>(() => ({ useGomokuStore }), [useGomokuStore])

  const { syncReplace } = useGomokuStore()
  React.useEffect(() => {
    if (initialState) syncReplace(() => initialState)
  }, [initialState, syncReplace])

  const onStateChange: StateListener<IGomokuStore> = useEvent((store, prevStore) => {
    if (!shallow(store.state, prevStore.state)) {
      void props.onStateChange?.(store.state)
    }
  })

  React.useEffect(() => {
    const unsubscribe = useGomokuStore.subscribe(onStateChange)
    return unsubscribe
  }, [useGomokuStore, onStateChange])

  React.useEffect(() => {
    return () => useGomokuStore?.destroy()
  }, [useGomokuStore])

  return <GomokuContextType.Provider value={context}>{props.children}</GomokuContextType.Provider>
}
