import React from 'react'
import type { GomokuPlayerType } from '../core/constant'
import { PlayerNameSetting } from './PlayerNameSetting'
import { PlayerTypeSettings } from './PlayerTypeSetting'
import { usePlayerSettingsStyle } from './styles'

export interface IHumanPlayerSettingsProps {
  name: string
  type: GomokuPlayerType
  disabled: boolean
  onNameChange(name: string): void
  onTypeChange(type: GomokuPlayerType): void
}

export const HumanPlayerSettings: React.FC<IHumanPlayerSettingsProps> = props => {
  const classes = usePlayerSettingsStyle()
  return (
    <div className={classes.settingForm}>
      <PlayerNameSetting
        label="Name"
        className={classes.formItem}
        name={props.name}
        disabled={props.disabled}
        onNameChange={props.onNameChange}
      />
      <PlayerTypeSettings
        label="Type"
        className={classes.formItem}
        type={props.type}
        disabled={props.disabled}
        onTypeChange={props.onTypeChange}
      />
    </div>
  )
}
