import { css, cx, keyframes } from '@emotion/css'
import AccessAlarmIcon from '@mui/icons-material/AccessAlarm'
import React from 'react'
import type { GomokuPlayerType } from '../core/constant'

export interface IDuelPlayerProps {
  name: string
  type: GomokuPlayerType
  disabled: boolean
  thinking: boolean
  running: boolean
  className?: string
  onEdit(): void
}

export const DuelPlayer: React.FC<IDuelPlayerProps> = props => {
  const classes = useStyles(props.disabled, props.thinking, props.running)
  return (
    <div className={cx(classes.container, props.className)} onClick={props.onEdit}>
      <span className={classes.name}>
        {props.name}
        <AccessAlarmIcon className={classes.thinkingIcon} />
      </span>
      <span className={classes.type}>{props.type}</span>
    </div>
  )
}

const useStyles = (disabled: boolean, thinking: boolean, running: boolean) => {
  return React.useMemo(
    () => ({
      container: css({
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        lineHeight: '16px',
        cursor: disabled ? 'default' : 'pointer',
      }),
      name: css({
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
        color: '#4682b4',
        fontSize: 16,
        userSelect: 'none',
      }),
      thinkingIcon: css({
        '&&': {
          position: 'absolute',
          top: 0,
          right: -20,
          display: 'inline-block',
          visibility: thinking ? 'visible' : 'hidden',
          transition: 'translate(0, -50%)',
          width: 16,
          height: 16,
          color: '#69696e',
          userSelect: 'none',
          animation: running
            ? `1s ease-in 0s ${animations.thinkingIcon} infinite alternate both`
            : undefined,
        },
      }),
      type: css({
        margin: '4px 0',
        fontSize: 14,
        userSelect: 'none',
      }),
    }),
    [disabled, thinking, running],
  )
}

const animations = {
  thinkingIcon: keyframes({
    '0%': {
      transform: 'rotate(-30deg) scale(1.0)',
    },
    '50%': {
      transform: 'rotate(0deg) scale(1.2)',
    },
    '100%': {
      transform: 'rotate(30deg) scale(1.0)',
    },
  }),
}
