import type { ICircularQueue } from '@algorithm.ts/circular-queue'
import { createCircularQueue } from '@algorithm.ts/circular-queue'
import invariant from '@guanghechen/invariant'
import { KyokuyaWorker } from './worker'

export interface IWebWorkerTaskSchedulerProps {
  canUseDOM: boolean
  workerInstanceCount: number
  workerUrl: string | URL
  workerOptions?: WorkerOptions
  MAX_TASK_NUMBER?: number
}

export class WebWorkerTaskScheduler<T extends string, D, R> {
  protected readonly workers: Array<KyokuyaWorker<T, D, R>>
  protected readonly tasks: ICircularQueue<ScheduleTaskItem<D, R>>
  protected readonly taskMap: Map<number, ScheduleTaskItem<D, R>>
  protected requestId: number

  constructor(props: IWebWorkerTaskSchedulerProps) {
    const instanceCount: number = Math.max(1, Math.min(100, props.workerInstanceCount))

    this.requestId = 0
    this.tasks = createCircularQueue()
    this.tasks.init(props.MAX_TASK_NUMBER ?? 1e4)
    this.taskMap = new Map()
    this.workers = new Array(instanceCount).fill([]).map(
      () =>
        new KyokuyaWorker({
          canUseDOM: props.canUseDOM,
          scriptURL: props.workerUrl,
          options: props.workerOptions,
          onResponse: e => {
            const { id, data, error } = e.data

            const task = this.tasks.get(id, false)
            invariant(
              task !== undefined,
              () => `[Webworker] Cannot find the running task with id (${id})`,
            )

            switch (task.status) {
              case 'running': {
                if (data === null) task.reject(`[Webworker] Cannot solve the request. ${error}`)
                else task.resolve(data)

                task.status = 'done'
                break
              }
              case 'pending':
              case 'done':
                throw new Error(`[Webworker] Bad task status (${task.status}). id (${id})`)
              case 'canceled':
                break
            }
            this.schedule()
          },
        }),
    )
  }

  public run(type: T, data: D, ownerId = 0): Promise<R | null> {
    const { tasks, taskMap } = this
    return new Promise<R | null>((resolve, reject) => {
      const nextTask: ScheduleTaskItem<D, R> = {
        id: -1,
        type,
        data,
        status: 'pending',
        resolve,
        reject,
      }

      const previousTask = taskMap.get(ownerId)
      if (previousTask === undefined) {
        nextTask.id = tasks.enqueue(nextTask)
      } else if (previousTask !== undefined) {
        switch (previousTask.status) {
          case 'pending': {
            previousTask.status = 'canceled'
            previousTask.resolve(null)
            nextTask.id = previousTask.id
            tasks.set(previousTask.id, nextTask)
            break
          }
          case 'running':
          case 'canceled':
          case 'done':
            nextTask.id = tasks.enqueue(nextTask)
            break
        }
      }

      taskMap.set(ownerId, nextTask)
      this.schedule()
    })
  }

  protected schedule(): void {
    const worker = this.workers.find(worker => !worker.isRunning)
    if (worker === undefined) return

    const { tasks } = this
    let task: ScheduleTaskItem<D, R> | undefined
    while (!tasks.isEmpty()) {
      task = tasks.dequeue()!
      if (task.status === 'pending') break
    }

    // No valid task found.
    if (task === undefined || task.status !== 'pending') return

    task.status = 'running'
    worker.request({ id: task.id, type: task.type as T, data: task.data })
  }
}

/**
 * Task item.
 */
export interface ScheduleTaskItem<D, R> {
  /**
   * Task identifier.
   */
  id: number
  /**
   * Service type.
   */
  type: string
  /**
   * Request data.
   */
  data: D
  /**
   * Does the task alive.
   */
  status: 'pending' | 'running' | 'canceled' | 'done'
  /**
   * Callback function after the task execution succeed.
   * @param data
   */
  resolve(data: R | null): void
  /**
   * Callback function after task execution fails.
   * @param error
   */
  reject(error: any): void
}
