import { css, cx } from '@emotion/css'
import { useEvent } from '@kyokuya/react-hooks'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select } from '@mui/material'
import React from 'react'

export interface IGameSettingsGomokuSizeProps {
  size: number
  disabled: boolean
  className?: string
  onSizeChange?(size: number): void
}

export const GameSettingsGomokuSize: React.FC<IGameSettingsGomokuSizeProps> = props => {
  const { size, disabled } = props
  const events = {
    onSizeChange: useEvent((e: SelectChangeEvent<number>): void => {
      const value = Number(e.target.value)
      props.onSizeChange?.(value)
    }),
  }

  const classes = useStyles()
  return (
    <div className={cx(classes.container, props.className)}>
      <span className={classes.label}>Board Size:</span>
      <Select
        className={classes.input}
        variant="standard"
        value={size}
        disabled={disabled}
        onChange={events.onSizeChange}
      >
        <MenuItem value={5}>5x5</MenuItem>
        <MenuItem value={7}>7x7</MenuItem>
        <MenuItem value={9}>9x9</MenuItem>
        <MenuItem value={11}>11x11</MenuItem>
        <MenuItem value={13}>13x13</MenuItem>
        <MenuItem value={15}>15x15</MenuItem>
        <MenuItem value={17}>17x17</MenuItem>
        <MenuItem value={19}>19x19</MenuItem>
        <MenuItem value={21}>21x21</MenuItem>
        <MenuItem value={23}>23x23</MenuItem>
        <MenuItem value={25}>2525</MenuItem>
      </Select>
    </div>
  )
}

const useStyles = () => ({
  container: css`
    display: flex;
    align-items: center;
  `,
  label: css`
  `,
  input: css`
    && {
      margin-left: 1rem;
    }
  `,
})
