import { GomokuDirections } from '@algorithm.ts/gomoku'
import shuffle from '@algorithm.ts/knuth-shuffle'
import type { IMoveContext, IPlayer } from '../../types'
import { GomokuPlayerType } from '../constant'
import { BasePlayer } from './BasePlayer'

export class StupidComputerPlayer extends BasePlayer implements IPlayer {
  public readonly type: GomokuPlayerType = GomokuPlayerType.STUPID_COMPUTER
  public readonly automatic: boolean = true

  protected override _move(ctx: IMoveContext): [r: number, c: number] {
    const { MAX_ROW, MAX_COL } = ctx
    if (ctx.pieces.length <= 0) {
      const mr: number = MAX_ROW >> 1
      const mc: number = MAX_COL >> 1
      return [mr, mc]
    }

    const pieces = ctx.pieces.slice()
    shuffle(pieces)

    const directions = GomokuDirections.slice()
    shuffle(directions)

    for (const piece of pieces) {
      for (const [dr, dc] of directions) {
        const nr: number = piece.r + dr
        const nc: number = piece.c + dc
        if (nr >= 0 && nr < MAX_ROW && nc >= 0 && nc < MAX_COL) {
          if (pieces.find(piece => piece.r === nr && piece.c === nc)) continue
          return [nr, nc]
        }
      }
    }
    return [-1, -1]
  }
}
